import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { getDashboardPathByRole } from "../utils/auth";

function Login() {
  const navigate = useNavigate();
  const { loginUser, isAuthenticated, user } = useAuth();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loginAs, setLoginAs] = useState("USER");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    if (isAuthenticated) {
      navigate(getDashboardPathByRole(user?.role), { replace: true });
    }
  }, [isAuthenticated, navigate, user]);

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError("");

    if (!email.trim() || !password) {
      setError("Email and password are required.");
      return;
    }

    try {
      setLoading(true);
      const data = await loginUser(email.trim(), password, loginAs);
      navigate(getDashboardPathByRole(data?.user?.role), { replace: true });
    } catch (err) {
      setError(err?.response?.data?.message || err?.message || "Login failed.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-shell">
      <div className="container auth-container">
        <div className="row g-4 align-items-stretch">
          <div className="col-lg-6">
            <div className="auth-panel h-100">
              <p className="eyebrow mb-2">Compliance Management System</p>
              <h2 className="mb-2">Sign In</h2>
              <p className="text-muted mb-4">Access your dashboard and track complaints in real-time.</p>

              {error && <div className="alert alert-danger">{error}</div>}

              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="loginAs" className="form-label">
                    Login As
                  </label>
                  <select
                    id="loginAs"
                    className="form-select"
                    value={loginAs}
                    onChange={(event) => setLoginAs(event.target.value)}
                  >
                    <option value="USER">User</option>
                    <option value="ADMIN">Admin</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label htmlFor="email" className="form-label">
                    Email
                  </label>
                  <input
                    id="email"
                    className="form-control"
                    placeholder="name@company.com"
                    type="email"
                    value={email}
                    onChange={(event) => setEmail(event.target.value)}
                  />
                </div>

                <div className="mb-3">
                  <label htmlFor="password" className="form-label">
                    Password
                  </label>
                  <input
                    id="password"
                    className="form-control"
                    placeholder="Enter your password"
                    type="password"
                    value={password}
                    onChange={(event) => setPassword(event.target.value)}
                  />
                </div>

                <button type="submit" className="btn btn-primary w-100" disabled={loading}>
                  {loading ? "Logging in..." : "Login"}
                </button>
              </form>

              <p className="compact-note mt-3 mb-0">
                User flow: Register, login, submit complaint, and track status. Admin flow: login,
                assign, investigate, update status, and generate reports.
              </p>

              <p className="mt-3 mb-0 text-center">
                New user? <Link to="/register">Create account</Link>
              </p>
            </div>
          </div>

          <div className="col-lg-6">
            <div className="auth-side-panel h-100 d-flex flex-column">
              <p className="eyebrow mb-2">Platform Highlights</p>
              <h3 className="mb-2">From Submission to Resolution</h3>
              <p className="mb-3 opacity-75">
                A clean command center for users and admins to collaborate on complaints with full
                visibility.
              </p>

              <ul className="list-group list-group-flush auth-steps mb-3">
                <li className="list-group-item">1. User registers and logs in</li>
                <li className="list-group-item">2. Complaint is submitted with optional evidence</li>
                <li className="list-group-item">3. Admin assigns and investigates the case</li>
                <li className="list-group-item">4. Admin replies and resolves with report export</li>
              </ul>

              <div className="d-flex flex-wrap gap-2 mt-auto">
                <span className="badge text-bg-light">Real-time tracking</span>
                <span className="badge text-bg-light">Role-based routing</span>
                <span className="badge text-bg-light">CSV reporting</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;
